"use client";

import { useState, useRef, useEffect, useCallback } from "react";
import { Mic, Send, Radio, User } from "lucide-react";
import styles from "./InputBar.module.css";
import { useStore } from "@/lib/store/useStore";
import { parseCommand, executeCommand } from "@/lib/ai/engine";
import { motion, AnimatePresence } from "framer-motion";

export default function InputBar() {
  const [input, setInput] = useState("");
  const [isListening, setIsListening] = useState(false);
  const [previewCustomer, setPreviewCustomer] = useState<any>(null);
  const { customers, addAiLog, setOrbState, searchCustomer } = useStore();
  
  const recognitionRef = useRef<any>(null);

  // Live search as user types
  useEffect(() => {
    if (input.length >= 2) {
      const found = searchCustomer(input);
      setPreviewCustomer(found || null);
    } else {
      setPreviewCustomer(null);
    }
  }, [input, searchCustomer]);

  const handleSend = useCallback(async (textOverride?: string) => {
    const command = textOverride || input.trim();
    if (!command) return;

    setInput("");
    setPreviewCustomer(null);
    
    // If we have a preview and it's just the name, treat as quick search
    if (previewCustomer && command.length < 20) {
      await addAiLog({
        command: `Quick Action: ${command}`,
        response: `Managing records for ${previewCustomer.name}:`,
        intent: 'show_balance',
        timestamp: new Date(),
        type: 'customer_card',
        data: previewCustomer
      });
      return;
    }

    const parseResult = parseCommand(command, customers);
    const response = await executeCommand(parseResult);

    await addAiLog({
      command,
      response,
      intent: parseResult.intent,
      timestamp: new Date()
    });
  }, [input, customers, addAiLog, previewCustomer]);

  useEffect(() => {
    if (typeof window !== "undefined") {
      const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
      if (SpeechRecognition) {
        recognitionRef.current = new SpeechRecognition();
        recognitionRef.current.continuous = true;
        recognitionRef.current.interimResults = true;
        recognitionRef.current.lang = 'en-IN';

        recognitionRef.current.onresult = (event: any) => {
          let currentTranscript = "";
          for (let i = event.resultIndex; i < event.results.length; ++i) {
            if (event.results[i].isFinal) {
              handleSend(event.results[i][0].transcript);
            } else {
              currentTranscript += event.results[i][0].transcript;
            }
          }
          if (currentTranscript) setInput(currentTranscript);
        };

        recognitionRef.current.onend = () => {
          if (isListening) recognitionRef.current.start();
        };
      }
    }
  }, [isListening, handleSend]);

  const toggleListening = () => {
    if (isListening) {
      setIsListening(false);
      recognitionRef.current?.stop();
      setOrbState('idle');
    } else {
      setIsListening(true);
      setOrbState('listening');
      recognitionRef.current?.start();
    }
  };

  return (
    <div className={styles.container}>
      <AnimatePresence>
        {previewCustomer && (
          <motion.div 
            initial={{ opacity: 0, y: 10, scale: 0.95 }}
            animate={{ opacity: 1, y: 0, scale: 1 }}
            exit={{ opacity: 0, y: 10, scale: 0.95 }}
            className={styles.previewCard}
            onClick={() => handleSend(previewCustomer.name)}
          >
            <User size={16} className={styles.previewIcon} />
            <div className={styles.previewInfo}>
              <strong>{previewCustomer.name}</strong>
              <span>₹{previewCustomer.totalDue} Due • Click for actions</span>
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      <div className={styles.inputWrapper}>
        <button 
          className={`${styles.micButton} ${isListening ? styles.listening : ''}`}
          onClick={toggleListening}
        >
          {isListening ? <Radio size={20} className={styles.pulse} /> : <Mic size={20} />}
        </button>

        <input 
          type="text" 
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={(e) => e.key === 'Enter' && handleSend()}
          placeholder={isListening ? "Listening..." : "Type a name or command..."}
          className={styles.input}
        />

        <button 
          className={styles.sendButton} 
          onClick={() => handleSend()}
          disabled={!input.trim()}
        >
          <Send size={20} />
        </button>
      </div>
    </div>
  );
}
