"use client";

import { useEffect, useRef, useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import styles from "./ConversationEngine.module.css";
import { useStore } from "@/lib/store/useStore";
import { format } from "date-fns";
import { UserPlus, IndianRupee, Phone, Check, X, Save, Camera, Send, MessageSquare } from "lucide-react";

export default function ConversationEngine() {
  const aiLogs = useStore((state) => state.aiLogs);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [aiLogs]);

  return (
    <div className={styles.container} ref={scrollRef}>
      <AnimatePresence initial={false}>
        {aiLogs.length === 0 ? (
          <div className={styles.empty}>
            <p>Ready for your first command...</p>
          </div>
        ) : (
          aiLogs.map((log, index) => (
            <div key={log.id || index} className={styles.messageGroup}>
              {log.command !== "System: Request New Customer Registration" && (
                <motion.div 
                  initial={{ opacity: 0, y: 10 }}
                  animate={{ opacity: 1, y: 0 }}
                  className={styles.userMessage}
                >
                  <span className={styles.text}>{log.command}</span>
                  <span className={styles.time}>{format(new Date(log.timestamp), 'HH:mm')}</span>
                </motion.div>
              )}

              <motion.div 
                initial={{ opacity: 0, x: -10 }}
                animate={{ opacity: 1, x: 0 }}
                transition={{ delay: 0.1 }}
                className={styles.aiMessage}
              >
                <div className={styles.aiBadge}>AI</div>
                <div className={styles.aiContent}>
                  <span className={styles.text}>{log.response}</span>
                  
                  {/* Interactive Cards */}
                  {log.type === 'form_new' && <NewCustomerForm id={log.id!} />}
                  {log.type === 'customer_card' && <CustomerActionCard customer={log.data} id={log.id!} />}
                </div>
              </motion.div>
            </div>
          ))
        )}
      </AnimatePresence>
    </div>
  );
}

function NewCustomerForm({ id }: { id: number }) {
  const [name, setName] = useState("");
  const [phone, setPhone] = useState("");
  const [photo, setPhoto] = useState<string | null>(null);
  const { addCustomer, setOrbState } = useStore();
  const [saved, setSaved] = useState(false);

  const handlePhotoChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setPhoto(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = async () => {
    if (!name) return;
    setOrbState('processing');
    await addCustomer({
      name,
      phone,
      photo: photo || undefined,
      totalDue: 0,
      lastTransactionDate: new Date(),
      status: 'active'
    });
    setOrbState('success');
    setSaved(true);
  };

  if (saved) return <div className={styles.savedMsg}><Check size={14} /> Customer Added Successfully!</div>;

  return (
    <div className={styles.card}>
      <div className={styles.photoUpload}>
        {photo ? (
          <img src={photo} alt="Preview" className={styles.photoPreview} />
        ) : (
          <div className={styles.photoPlaceholder}>
            <Camera size={20} />
            <input type="file" accept="image/*" onChange={handlePhotoChange} />
          </div>
        )}
        <span>{photo ? "Change Photo" : "Add Customer Photo"}</span>
      </div>
      <div className={styles.inputGroup}>
        <UserPlus size={14} />
        <input type="text" placeholder="Full Name" value={name} onChange={(e) => setName(e.target.value)} />
      </div>
      <div className={styles.inputGroup}>
        <Phone size={14} />
        <input type="text" placeholder="WhatsApp Number" value={phone} onChange={(e) => setPhone(e.target.value)} />
      </div>
      <button className={styles.saveBtn} onClick={handleSubmit}><Save size={14} /> Create Account</button>
    </div>
  );
}

function CustomerActionCard({ customer, id }: { customer: any, id: number }) {
  const { addTransaction, updateCustomer, setOrbState, transactions } = useStore();
  const [showInput, setShowInput] = useState<'credit' | 'payment' | 'phone' | null>(null);
  const [value, setValue] = useState("");
  const [desc, setDesc] = useState("");

  const handleAction = async () => {
    setOrbState('processing');
    if (showInput === 'credit' || showInput === 'payment') {
      await addTransaction({
        customerId: customer.id,
        amount: parseInt(value),
        type: showInput,
        description: desc || (showInput === 'credit' ? 'Credit Purchase' : 'Balance Payment'),
        timestamp: new Date()
      });
    } else if (showInput === 'phone') {
      await updateCustomer(customer.id, { phone: value });
    }
    setOrbState('success');
    setShowInput(null);
    setValue("");
    setDesc("");
  };

  const sendWhatsAppSummary = () => {
    if (!customer.phone) return alert("Please add a phone number first.");
    const customerTransactions = transactions.filter(t => t.customerId === customer.id).slice(0, 5);
    let message = `Hello ${customer.name}, here is your account summary:\n\n`;
    message += `Total Balance Due: ₹${customer.totalDue}\n\n`;
    message += `Recent Transactions:\n`;
    customerTransactions.forEach(t => {
      message += `- ${format(t.timestamp, 'dd MMM')}: ₹${t.amount} (${t.type === 'credit' ? 'Udhar' : 'Paid'}) ${t.description ? `- ${t.description}` : ''}\n`;
    });
    message += `\nPlease clear your pending balance. Thank you!`;
    
    const encoded = encodeURIComponent(message);
    window.open(`https://wa.me/${customer.phone}?text=${encoded}`, '_blank');
  };

  return (
    <div className={styles.card}>
      <div className={styles.cardHeader}>
        <div className={styles.customerSummary}>
          {customer.photo && <img src={customer.photo} className={styles.miniPhoto} />}
          <div>
            <strong>{customer.name}</strong>
            <span className={styles.dueSub}>₹{customer.totalDue} Total Due</span>
          </div>
        </div>
      </div>
      
      {!showInput ? (
        <div className={styles.actionGrid}>
          <button onClick={() => setShowInput('credit')}>Add Udhar</button>
          <button onClick={() => setShowInput('payment')}>Paid</button>
          <button className={styles.waAction} onClick={sendWhatsAppSummary}>
            <MessageSquare size={14} /> Summary
          </button>
          <button onClick={() => setShowInput('phone')} className={styles.secondaryBtn}>Number</button>
        </div>
      ) : (
        <div className={styles.actionForm}>
          <div className={styles.inputBox}>
            <input 
              type={showInput === 'phone' ? 'text' : 'number'} 
              placeholder={showInput === 'phone' ? "Enter New Number" : "Amount (₹)"}
              value={value}
              onChange={(e) => setValue(e.target.value)}
              autoFocus
            />
            {showInput !== 'phone' && (
              <input 
                type="text"
                placeholder="Item / Description"
                value={desc}
                onChange={(e) => setDesc(e.target.value)}
                className={styles.descInput}
              />
            )}
          </div>
          <div className={styles.formActions}>
            <button className={styles.confirm} onClick={handleAction}><Check size={14} /> Confirm</button>
            <button className={styles.cancel} onClick={() => setShowInput(null)}><X size={14} /></button>
          </div>
        </div>
      )}
    </div>
  );
}
