"use client";

import { motion } from "framer-motion";
import styles from "./AiOrb.module.css";
import { useStore } from "@/lib/store/useStore";

export default function AiOrb() {
  const orbState = useStore((state) => state.orbState);

  const getGlowColor = () => {
    switch (orbState) {
      case 'listening': return 'var(--primary-green)';
      case 'processing': return 'var(--accent-blue)';
      case 'success': return 'var(--primary-green)';
      case 'error': return 'var(--accent-orange)';
      default: return 'var(--primary-green)';
    }
  };

  return (
    <div className={styles.container}>
      <div className={styles.orbWrapper}>
        <motion.div 
          className={styles.orb}
          animate={{
            backgroundColor: getGlowColor(),
            boxShadow: `0 0 50px ${getGlowColor()}`,
            scale: orbState === 'listening' ? [1, 1.15, 1] : 1
          }}
          transition={{ duration: 0.5 }}
        >
          <div className={styles.core} />
        </motion.div>

        {orbState === 'listening' && (
          <motion.div 
            className={styles.wave}
            initial={{ scale: 1, opacity: 0.4 }}
            animate={{ scale: 1.8, opacity: 0 }}
            transition={{ duration: 1.5, repeat: Infinity }}
            style={{ borderColor: getGlowColor() }}
          />
        )}
      </div>
      <p className={styles.statusText}>
        {orbState === 'idle' && "Assistant Ready"}
        {orbState === 'listening' && "Listening to you..."}
        {orbState === 'processing' && "Thinking..."}
        {orbState === 'success' && "Done!"}
        {orbState === 'error' && "Let's try again"}
      </p>
    </div>
  );
}
