import { db } from './dexie';

export const seedDatabase = async () => {
  const customerCount = await db.customers.count();
  if (customerCount > 0) return;

  const initialCustomers = [
    {
      name: "Ramesh Kumar",
      phone: "9876543210",
      totalDue: 2450,
      lastTransactionDate: new Date(Date.now() - 5 * 24 * 60 * 60 * 1000),
      status: 'overdue' as const
    },
    {
      name: "Suresh Singh",
      phone: "8877665544",
      totalDue: 1200,
      lastTransactionDate: new Date(Date.now() - 2 * 24 * 60 * 60 * 1000),
      status: 'active' as const
    },
    {
      name: "Anita Devi",
      phone: "7766554433",
      totalDue: 0,
      lastTransactionDate: new Date(Date.now() - 1 * 24 * 60 * 60 * 1000),
      status: 'active' as const
    }
  ];

  const ids = await db.customers.bulkAdd(initialCustomers, { allKeys: true });
  
  // Add some transactions for Ramesh
  await db.transactions.bulkAdd([
    {
      customerId: ids[0],
      amount: 2000,
      type: 'credit',
      description: 'Monthly Groceries',
      timestamp: new Date(Date.now() - 10 * 24 * 60 * 60 * 1000)
    },
    {
      customerId: ids[0],
      amount: 450,
      type: 'credit',
      description: 'Rice & Oil',
      timestamp: new Date(Date.now() - 5 * 24 * 60 * 60 * 1000)
    }
  ]);

  // Add initial AI logs
  await db.ai_logs.add({
    command: "Show Ramesh balance",
    response: "Ramesh has a pending balance of ₹2450.",
    intent: "show_balance",
    timestamp: new Date()
  });
};
