"use client";

import { useState } from "react";
import { useStore } from "@/lib/store/useStore";
import styles from "./ManualEntry.module.css";
import { UserPlus, PlusCircle, IndianRupee, Save, X } from "lucide-react";

export default function ManualEntry() {
  const [activeTab, setActiveTab] = useState<'customer' | 'transaction' | null>(null);
  const { customers, addCustomer, addTransaction } = useStore();

  // Form States
  const [customerName, setCustomerName] = useState("");
  const [phone, setPhone] = useState("");
  const [selectedCustomerId, setSelectedCustomerId] = useState("");
  const [amount, setAmount] = useState("");
  const [type, setType] = useState<'credit' | 'payment'>('credit');

  const handleAddCustomer = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!customerName) return;
    await addCustomer({
      name: customerName,
      phone: phone,
      totalDue: 0,
      lastTransactionDate: new Date(),
      status: 'active'
    });
    setCustomerName("");
    setPhone("");
    setActiveTab(null);
  };

  const handleAddTransaction = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedCustomerId || !amount) return;
    await addTransaction({
      customerId: parseInt(selectedCustomerId),
      amount: parseInt(amount),
      type: type,
      description: 'Manual Entry',
      timestamp: new Date()
    });
    setAmount("");
    setSelectedCustomerId("");
    setActiveTab(null);
  };

  return (
    <div className={styles.container}>
      <div className={styles.tabs}>
        <button 
          className={`${styles.tabBtn} ${activeTab === 'customer' ? styles.active : ''}`}
          onClick={() => setActiveTab(activeTab === 'customer' ? null : 'customer')}
        >
          <UserPlus size={16} />
          New Customer
        </button>
        <button 
          className={`${styles.tabBtn} ${activeTab === 'transaction' ? styles.active : ''}`}
          onClick={() => setActiveTab(activeTab === 'transaction' ? null : 'transaction')}
        >
          <PlusCircle size={16} />
          Add Entry
        </button>
      </div>

      {activeTab === 'customer' && (
        <form className={styles.form} onSubmit={handleAddCustomer}>
          <input 
            type="text" 
            placeholder="Name" 
            value={customerName}
            onChange={(e) => setCustomerName(e.target.value)}
            className={styles.input}
          />
          <input 
            type="text" 
            placeholder="Phone (optional)" 
            value={phone}
            onChange={(e) => setPhone(e.target.value)}
            className={styles.input}
          />
          <button type="submit" className={styles.submitBtn}><Save size={16} /> Save</button>
          <button type="button" onClick={() => setActiveTab(null)} className={styles.cancelBtn}><X size={16} /></button>
        </form>
      )}

      {activeTab === 'transaction' && (
        <form className={styles.form} onSubmit={handleAddTransaction}>
          <select 
            value={selectedCustomerId}
            onChange={(e) => setSelectedCustomerId(e.target.value)}
            className={styles.input}
          >
            <option value="">Select Customer</option>
            {customers.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
          </select>
          <div className={styles.amountGroup}>
            <span className={styles.currency}>₹</span>
            <input 
              type="number" 
              placeholder="Amount" 
              value={amount}
              onChange={(e) => setAmount(e.target.value)}
              className={styles.input}
            />
          </div>
          <div className={styles.typeToggle}>
            <button 
              type="button"
              className={`${styles.toggleBtn} ${type === 'credit' ? styles.activeCredit : ''}`}
              onClick={() => setType('credit')}
            >
              Udhaar
            </button>
            <button 
              type="button"
              className={`${styles.toggleBtn} ${type === 'payment' ? styles.activePayment : ''}`}
              onClick={() => setType('payment')}
            >
              Jama
            </button>
          </div>
          <button type="submit" className={styles.submitBtn}><Save size={16} /> Add</button>
          <button type="button" onClick={() => setActiveTab(null)} className={styles.cancelBtn}><X size={16} /></button>
        </form>
      )}
    </div>
  );
}
