"use client";

import { UserPlus, Sparkles } from "lucide-react";
import AiOrb from "./AiOrb";
import ConversationEngine from "./ConversationEngine";
import InputBar from "./InputBar";
import styles from "./AiAssistant.module.css";
import { useStore } from "@/lib/store/useStore";

export default function AiAssistant() {
  const { addAiLog, setOrbState } = useStore();

  const handleNewCustomerForm = async () => {
    setOrbState('processing');
    await addAiLog({
      command: "System: Request New Customer Registration",
      response: "Of course! I've opened the registration form for you below.",
      intent: "add_customer",
      timestamp: new Date(),
      type: 'form_new'
    });
    setOrbState('success');
  };

  return (
    <div className={styles.container}>
      <header className={styles.header}>
        <div className={styles.titleGroup}>
          <div className={styles.pulseDot} />
          <span>AI OPERATING SYSTEM</span>
        </div>
        <button className={styles.newBtn} onClick={handleNewCustomerForm}>
          <UserPlus size={16} />
          <span>NEW CUSTOMER</span>
        </button>
      </header>
      
      <AiOrb />
      <div className={styles.divider} />
      <ConversationEngine />
      <InputBar />
    </div>
  );
}
