"use client";

import { useEffect } from "react";
import { useStore } from "@/lib/store/useStore";
import StatsCards from "./StatsCards";
import ManualEntry from "./ManualEntry";
import OverdueList from "./OverdueList";
import CustomerLedger from "./CustomerLedger";
import styles from "./BusinessDashboard.module.css";
import { Settings, Wifi, WifiOff, RefreshCcw } from "lucide-react";

import { seedDatabase } from "@/lib/db/seed";

export default function BusinessDashboard() {
  const { fetchData, isLoading } = useStore();

  useEffect(() => {
    const init = async () => {
      await seedDatabase();
      await fetchData();
    };
    init();
  }, [fetchData]);

  if (isLoading) {
    return <div className={styles.loading}>Initializing Dashboard...</div>;
  }

  return (
    <div className={styles.container}>
      {/* Header */}
      <header className={styles.header}>
        <div className={styles.shopInfo}>
          <h1 className={styles.shopName}>Kirana AI OS</h1>
          <div className={styles.statusBadge}>
            <Wifi size={14} className={styles.onlineIcon} />
            <span>Live Sync Active</span>
          </div>
        </div>
        <div className={styles.headerActions}>
          <button className={styles.iconButton} onClick={() => fetchData()}>
            <RefreshCcw size={20} />
          </button>
          <button className={styles.iconButton}>
            <Settings size={20} />
          </button>
        </div>
      </header>

      <div className={styles.content}>
        <ManualEntry />
        <StatsCards />
        
        <div className={styles.grid}>
          <section className={styles.ledgerSection}>
            <div className={styles.sectionHeader}>
              <h2>Customer Ledger</h2>
              <span className={styles.badge}>Live</span>
            </div>
            <CustomerLedger />
          </section>

          <aside className={styles.overdueSection}>
            <div className={styles.sectionHeader}>
              <h2>Overdue Alerts</h2>
              <span className={`${styles.badge} ${styles.badgeRed}`}>Action Required</span>
            </div>
            <OverdueList />
          </aside>
        </div>
      </div>
    </div>
  );
}
